  const rawData = fs.readFileSync(problemsDataPath, 'utf8');
  problems = JSON.parse(rawData);
} catch (e) {
  problems = [];
}

/**
 * List problems with filtering, paging, and metadata.
 * @param {Object} options
 * @param {string} [options.difficulty] - Filter by difficulty (e.g. 'Easy', 'Medium', 'Hard')
 * @param {number} [options.limit=50] - Max number of results to return (max 50)
 * @param {boolean} [options.includeComponents=false] - Whether to include sorted componentLanguages
 * @returns {Object} result
 *   {
 *     problems: Array of problem objects,
 *     totalProblems: total number of problems in dataset,
 *     filteredCount: number of problems after filtering,
 *     appliedLimit: number of problems returned (<= limit),
 *     difficultyBreakdown: { Easy: n, Medium: n, Hard: n }
 *   }
 */
function listProblems({ difficulty, limit = 50, includeComponents = false } = {}) {
  // Validate limit
  if (typeof limit !== 'number' || limit <= 0) {
    limit = 50;
  }
  if (limit > 50) {
    limit = 50;
  }

  // Compute difficulty breakdown for all problems
  const difficultyBreakdown = problems.reduce((acc, p) => {
    const diff = p.difficulty || 'Unknown';
    acc[diff] = (acc[diff] || 0) + 1;
    return acc;
  }, {});

  // Filter problems by difficulty if provided
  let filtered = problems;
  if (difficulty) {
    filtered = filtered.filter(p => p.difficulty === difficulty);
  }

  // Sort filtered problems by roundId ascending (deterministic ordering)
  filtered.sort((a, b) => {
    if (a.roundId < b.roundId) return -1;
    if (a.roundId > b.roundId) return 1;
    return 0;
  });

  // Apply limit
  const limited = filtered.slice(0, limit);

  // If includeComponents is true, add sorted componentLanguages array to each problem
  if (includeComponents) {
    limited.forEach(p => {
      if (Array.isArray(p.componentLanguages)) {
        p.componentLanguages = p.componentLanguages.slice().sort();
      } else {
        p.componentLanguages = [];
      }
    });
  } else {
    // Remove componentLanguages if present to reduce payload
    limited.forEach(p => {
      if ('componentLanguages' in p) {
        delete p.componentLanguages;
      }
    });
  }

  return {
    problems: limited,
    totalProblems: problems.length,
    filteredCount: filtered.length,
    appliedLimit: limited.length,
    difficultyBreakdown
  };\
